import React, { useEffect, useState } from "react";
import InternshipCard from "../components/InternshipCard";
import InternshipModal from "../components/InternshipModal";
import "./Internship.css";

const dummyInternships = [
  {
    _id: "1",
    title: "Frontend Developer",
    company: "CodeTech Solutions",
    location: "Remote",
    stipend: "₹10,000/month",
    duration: "3 Months",
    description: "Work on React projects with real-world exposure.",
  },
  {
    _id: "2",
    title: "Data Analyst Intern",
    company: "DataSpark",
    location: "Mumbai",
    stipend: "₹15,000/month",
    duration: "2 Months",
    description: "Analyze datasets and generate business insights.",
  },
];

const Internship = () => {
  const [internships, setInternships] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedInternship, setSelectedInternship] = useState(null);
  const [appliedInternships, setAppliedInternships] = useState([]);
  const [userRole, setUserRole] = useState("student"); // Change to "admin" / "hr" for testing

  useEffect(() => {
    // Fetch internships from backend API here
    setInternships(dummyInternships);
  }, []);

  const filteredInternships = internships.filter((item) =>
    item.title.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleApply = (id) => {
    if (!appliedInternships.includes(id)) {
      setAppliedInternships([...appliedInternships, id]);
      alert("Applied successfully ✅");
    }
  };

  const handleDelete = (id) => {
    if (window.confirm("Are you sure you want to delete this internship?")) {
      setInternships(internships.filter((item) => item._id !== id));
    }
  };

  const handleEdit = (updatedItem) => {
    // For simplicity, just closing modal. Implement form if needed.
    alert("Edit feature not implemented in this version.");
    setSelectedInternship(null);
  };

  return (
    <div className="internship-page">
      <h1>Internships</h1>

      <input
        type="text"
        placeholder="Search internships..."
        value={searchTerm}
        onChange={(e) => setSearchTerm(e.target.value)}
        className="internship-search"
      />

      <div className="internship-list">
        {filteredInternships.map((internship) => (
          <InternshipCard
            key={internship._id}
            internship={internship}
            onClick={() => setSelectedInternship(internship)}
          />
        ))}
      </div>

      {selectedInternship && (
        <InternshipModal
          internship={selectedInternship}
          onClose={() => setSelectedInternship(null)}
          onApply={handleApply}
          onEdit={handleEdit}
          onDelete={handleDelete}
          userRole={userRole}
          hasApplied={appliedInternships.includes(selectedInternship._id)}
        />
      )}
    </div>
  );
};

export default Internship;
